import { catchAsync } from '@common/utils/catchAsync';
import { DEPARTMENT_BOF, UserRoleDefined } from '@common/utils/enum';
import EmployeesModel from '../../modules/employees/employees.model';
import { IDepartments } from '@common/interfaces/department.interface';
import { permissionRoutes } from '@config/permissionRoutes';
import { NextFunction, Request, Response } from 'express';
import { API_PREFIX } from '../../app';
import { PermissionService } from '@modules/permissions/permission.service';
import { ApiError } from '@common/utils/ApiError';

const permissionService = new PermissionService();

export const verifyAdmin = catchAsync(async (req, res, next): Promise<void> => {
    const user = req.users;
    if (user.roles === UserRoleDefined.Admin) {
        next();
        return;
    }

    const employee = await EmployeesModel.findById(user.user.employeeId).populate('departmentId');
    if ((employee?.departmentId as unknown as IDepartments)?.code === DEPARTMENT_BOF.CODE) {
        next();
        return;
    }

    throw new ApiError(403, 'Bạn không có quyền truy cập');
});

export const verifyAdminOrOwner = catchAsync(async (req, res, next): Promise<void> => {
    const user = req.users;
    const { id } = req.params;

    if (user.roles === UserRoleDefined.Admin) {
        next();
        return;
    }

    const employee = await EmployeesModel.findById(user.user.employeeId).populate('departmentId');
    if ((employee?.departmentId as unknown as IDepartments)?.code === DEPARTMENT_BOF.CODE) {
        next();
        return;
    }

    if (user.user.employeeId?.toString() === id) {
        next();
        return;
    }

    throw new ApiError(403, 'Bạn không có quyền truy cập');
});

export const normalizePath = (path: string): string => {
    return path.replace(/\/+$/, '') || '/';
};

export const buildRouteRegex = (route: string): RegExp => {
    const pattern = normalizePath(route)
        .replace(/:[^/]+/g, '[^/]+')
        .replace(/\*/g, '.*');

    return new RegExp(`^${pattern}$`);
};

export const matchPath = (route: string, path: string): boolean => {
    const cleanPath = normalizePath(path);
    const regex = buildRouteRegex(route);

    return regex.test(cleanPath);
};

export const authorizationPermissionMiddleware = catchAsync(async (req: Request, res: Response, next: NextFunction) => {
    const userRoleName = req.users?.roles;
    if (!userRoleName) {
        throw new ApiError(403, 'Bạn không có quyền truy cập');
    }

    const userPermissions = await permissionService.getPermissionsByRoleNameInCacheOfDB(userRoleName);

    if (userPermissions?.[0] === '*') {
        return next();
    }

    const currentMethod = req.method.toUpperCase();
    const currentPath = req.originalUrl.split('?')[0].replace(API_PREFIX, '').replace(/\/$/, '') || '/';

    let requiredPermission = '';
    let exactMatch: string = '';
    let dynamicMatch: string = '';

    for (const [moduleName, actions] of Object.entries(permissionRoutes)) {
        for (const [actionName, routes] of Object.entries(actions)) {
            const routeList = Array.isArray(routes) ? routes : [routes];
            for (const r of routeList) {
                if (r.method.toUpperCase() !== currentMethod) continue;

                const isDynamic = r.route.includes(':') || r.route.includes('*');

                if (matchPath(r.route, currentPath)) {
                    const permission = `${moduleName}.${actionName}`;

                    if (!isDynamic) {
                        exactMatch = permission;
                    } else if (!dynamicMatch) {
                        dynamicMatch = permission;
                    }
                }
            }
        }
    }

    if (exactMatch) {
        requiredPermission = exactMatch;
    } else if (dynamicMatch) {
        requiredPermission = dynamicMatch;
    }

    if (!requiredPermission) {
        throw new ApiError(403, 'Bạn không có quyền truy cập');
    }


    const hasPermission =
        userPermissions.includes(requiredPermission) || userPermissions.includes(`${requiredPermission.split('.')[0]}.*`);

    if (hasPermission) {
        return next();
    }

    throw new ApiError(403, 'Bạn không có quyền truy cập');
});

