import { Router } from 'express';
import { createAccount, deleteAccount, getAccountByFilter, getAccountById, updateAccount, changePasswordAccount } from './account.controller';
import { validate } from '@common/middlewares/validate.middleware';
import { createAccountSchema, updateAccountSchema, updateAccountPasswordSchema } from './accounts.validation';

const router = Router();

router.post('/', validate(createAccountSchema), createAccount);
router.patch('/change-password', validate(updateAccountPasswordSchema), changePasswordAccount);
router.patch('/:id', validate(updateAccountSchema), updateAccount);
router.delete('/:id', deleteAccount);
router.get('/:id', getAccountById);
router.get('/', getAccountByFilter);
export default router;

