import { JWT_PRIVATE_KEY } from '@common/config/environment';
import jwt, { SignOptions, TokenExpiredError } from 'jsonwebtoken';
import { ApiError } from './ApiError';

type ExpiresIn = SignOptions['expiresIn'];
export interface ITokenPayload {
    accountId: string;
    roleName: string;
    tokenVersion?: number;
    exp?: number;
}

export const generateToken = (payload: ITokenPayload, expiresIn: ExpiresIn): string => {
    const data: ITokenPayload = {
        accountId: payload.accountId,
        roleName: payload.roleName,
        tokenVersion: payload.tokenVersion,
    };

    const token = jwt.sign(data, JWT_PRIVATE_KEY, { expiresIn: expiresIn });

    return token;
};

export const verifyToken = (token: string): ITokenPayload => {
    try {
        const decoded = jwt.verify(token, JWT_PRIVATE_KEY) as ITokenPayload;

        return decoded;
    } catch (error) {
        if (error instanceof TokenExpiredError) {
            throw new ApiError(401, 'Access token đã hết hạn');
        }

        throw new ApiError(401, 'Access token không hợp lệ');
    }
};

